const auth = require('../src/auth');

describe('Authentication', () => {
  test('should hash passwords correctly', () => {
    const hashed = auth.hashPassword('password123');
    expect(hashed).toMatch(/^\$2b\$10\$/);
    expect(hashed).not.toBe('password123');
  });

  test('should validate email format', () => {
    expect(auth.isValidEmail('test@example.com')).toBe(true);
    expect(auth.isValidEmail('notanemail')).toBe(false);
  });

  test('should reject weak passwords', () => {
    expect(auth.isStrongPassword('ValidPass123!')).toBe(true);
    expect(auth.isStrongPassword('123')).toBe(false);
  });

  test('should create user tokens', () => {
    const token = auth.createToken({id: 1, email: 'test@example.com'});
    expect(token).toBeDefined();
  });
});

